import{_ as o,W as l,X as c,Z as e,$ as n,a0 as a,a1 as t,D as r}from"./framework-c9619a7b.js";const i={},p=t('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>Kubernetes（通常简称为&quot;k8s&quot;）是一个开源的容器编排和管理平台，由Google公司开发并捐赠给Cloud Native Computing Foundation（CNCF）管理。</p><p>Kubernetes旨在帮助用户更轻松地部署、扩展和管理应用程序，以及提高应用程序的可靠性和可伸缩性。它支持多种容器运行时，如Docker、CRI-O等，并提供了丰富的API和工具，以便用户更轻松地管理容器、应用程序和相关资源。</p><p>Kubernetes采用了微服务架构的思想，通过将应用程序拆分成多个小型、独立的服务，并将它们部署到容器中，来提高应用程序的可靠性和可维护性。同时，Kubernetes还提供了丰富的服务发现、负载均衡、容错和自动扩展等功能，以便用户更轻松地管理应用程序。</p><p>总之，Kubernetes是一个用于容器编排和管理的开源平台，旨在提高应用程序的可靠性和可伸缩性，支持多种容器运行时，并提供了丰富的API和工具，以便用户更轻松地管理容器、应用程序和相关资源。</p><h2 id="教程" tabindex="-1"><a class="header-anchor" href="#教程" aria-hidden="true">#</a> 教程</h2><h3 id="架构" tabindex="-1"><a class="header-anchor" href="#架构" aria-hidden="true">#</a> 架构</h3>',7),d={href:"https://devopscube.com/kubernetes-architecture-explained/",target:"_blank",rel:"noopener noreferrer"},u=t(`<figure><img src="https://minio.kevin2li.top/image-bed/blog/20230525165737.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="control-plane-components" tabindex="-1"><a class="header-anchor" href="#control-plane-components" aria-hidden="true">#</a> Control Plane Components</h4><ul><li><code>kube-apiserver</code></li></ul><p>在Kubernetes中，API Server是一个核心组件，它提供了Kubernetes API的前端，是Kubernetes集群中所有资源的唯一访问点。API Server充当了所有操作的统一网关，接收来自kubectl等客户端工具和其它Kubernetes组件的请求，然后根据请求的内容，向etcd存储库读取或更新状态，最后返回响应。</p><p>API Server为Kubernetes系统提供了一种强大的方式来控制、管理和监视各种资源和对象，例如Pod、Service、Deployment、ConfigMap、Secret等等。它还允许开发者通过自定义资源定义（Custom Resource Definitions）来扩展Kubernetes API，以支持特定于应用程序或行业的自定义资源类型。除此之外，API Server还提供了认证和授权机制，用于保护Kubernetes集群的安全。</p><ul><li><code>etcd</code></li></ul><p>在Kubernetes中，<code>etcd</code>是用于存储集群状态的分布式键值存储系统。它是一个高可用的、强一致性的、分布式系统，通常运行在Kubernetes集群的控制平面节点上。etcd存储着Kubernetes集群的配置数据、状态信息和元数据，包括了节点、服务、副本集、部署、配置文件等。etcd使用Raft算法来保证数据的一致性和可靠性，确保Kubernetes集群的高可用和稳定性。在Kubernetes中，API Server是与etcd进行交互的唯一组件。</p><ul><li><code>kube-scheduler</code></li></ul><p>在Kubernetes中，<code>Scheduler</code>是一个核心组件，它负责将新的Pod分配给可用的工作节点（Node）。当一个新的Pod被创建时，它会根据Pod的调度需求，如资源限制、亲和性、反亲和性等，选择一个最适合的节点进行调度。</p><p><code>Scheduler</code>通常运行在Kubernetes集群的控制平面节点上，它通过与API Server交互来了解当前的集群状态和Pod的调度需求，并将未调度的Pod与可用的节点进行匹配，从而完成Pod的调度过程。<code>Scheduler</code>是一个可插拔的组件，可以根据实际需求定制和扩展调度算法。同时，Kubernetes还提供了调度器调度策略和插件的配置，以满足不同的调度需求。</p><ul><li><code>kube-controller-manager</code></li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230525174332.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>在Kubernetes中，<code>Controller Manager</code>是一个核心组件，它负责管理集群中的控制器（Controller）。控制器是一类负责维护Kubernetes系统中期望状态和实际状态一致的核心组件，例如Replication Controller、Deployment、StatefulSet、DaemonSet等等。</p><p><code>Controller Manager</code>通常运行在Kubernetes集群的控制平面节点上，它通过与API Server交互来了解当前的集群状态，并根据期望状态与实际状态之间的差异，执行相应的操作，以确保集群的状态始终与期望状态一致。例如，当一个Pod被终止时，Replication Controller会创建一个新的Pod来替换它，以保持Pod的副本数量与期望值相同。</p><p><code>Controller Manager</code>是一个可插拔的组件，可以根据实际需求定制和扩展不同类型的控制器。同时，Kubernetes还提供了控制器的配置和管理方式，以满足不同的需求和场景。</p><ul><li><code>cloud-controller-manager</code></li></ul><p>在Kubernetes中，<code>Cloud Controller Manager</code>是一个可选组件，它负责管理与云平台相关的资源，例如负载均衡器、云盘、云存储等等。</p><p><code>Cloud Controller Manager</code>运行在Kubernetes集群的控制平面节点上，通过与云平台API交互来管理这些资源。它与Kubernetes API Server交互，接收Kubernetes系统中的资源请求，并将这些请求翻译成云平台API调用。例如，在AWS云平台上，<code>Cloud Controller Manager</code>可以创建和管理Elastic Load Balancer，将Kubernetes Service暴露为外部负载均衡器。在GCP上，<code>Cloud Controller Manager</code>可以管理Persistent Disk资源，为Pod提供持久化存储。</p><p><code>Cloud Controller Manager</code>是一个可插拔的组件，可以根据实际需求选择和配置不同类型的云平台资源。同时，Kubernetes还提供了云平台提供商相关的插件和配置选项，以方便云原生应用程序在不同云平台上的部署和管理。</p><h4 id="worker-node-components" tabindex="-1"><a class="header-anchor" href="#worker-node-components" aria-hidden="true">#</a> Worker Node Components</h4><ul><li><code>kubelet</code></li></ul><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230525165837.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>在Kubernetes中，<code>kubelet</code>是一个核心组件，它运行在每个节点上，负责管理节点上的容器和镜像。</p><p><code>kubelet</code>与Kubernetes API Server交互，获取当前节点上需要运行的Pod的信息，并根据这些信息创建、启动和停止相应的容器。同时，<code>kubelet</code>还负责监控这些容器的状态，并将容器的状态信息上报给Kubernetes API Server。</p><p><code>kubelet</code>还负责管理节点上的容器和镜像，包括拉取、删除和清理过期的镜像，以确保节点上的存储空间得到充分利用。</p><p>除了与Kubernetes API Server交互外，<code>kubelet</code>还通过容器运行时接口（如Docker、CRI-O、containerd等）与容器运行时进行通信，管理容器的生命周期，并监视容器的资源使用情况。</p><p>总之，<code>kubelet</code>是Kubernetes集群中非常重要的一个组件，它负责将Kubernetes集群中的抽象概念（如Pod、容器）转化为在节点上运行的实际进程，是Kubernetes集群中实现容器编排和管理的关键组件之一。</p><ul><li><code>kube-proxy</code></li></ul><p>在Kubernetes中，<code>kube-proxy</code>是一个核心组件，它运行在每个节点上，负责实现Kubernetes Service的网络代理和负载均衡功能。</p><p><code>kube-proxy</code>通过监视Kubernetes API Server上的Service和Endpoint对象，了解哪些Service需要暴露到集群内部和外部，并且哪些后端Pod是Service的目标。然后，<code>kube-proxy</code>通过在节点上配置iptables规则或者ipvs规则（如果使用ipvs模式）来实现服务的负载均衡和代理。</p><p>当Service的Cluster IP被请求时，<code>kube-proxy</code>会使用相应的负载均衡算法选择一个后端Pod，并将请求转发给该Pod，从而实现服务的访问。此外，<code>kube-proxy</code>还可以支持通过NodePort和LoadBalancer等方式将Service暴露到集群外部，并实现相应的网络代理和负载均衡功能。</p><p>总之，<code>kube-proxy</code>是Kubernetes集群中非常重要的一个组件，它负责实现Kubernetes Service的网络代理和负载均衡功能，是Kubernetes集群中实现服务发现和负载均衡的关键组件之一。</p><ul><li><code>Container runtime</code></li></ul><p>在Kubernetes中，Container runtime是指运行容器的软件。Kubernetes支持多种容器运行时，如Docker、CRI-O、containerd等。</p><p>容器运行时负责管理容器的生命周期，包括创建、启动、停止和销毁容器。容器运行时还负责管理容器的文件系统、网络和进程等资源，并确保容器能够在隔离的环境中运行。</p><p>在Kubernetes中，kubelet通过与容器运行时的接口（如Docker API、CRI-O API等）进行通信，与容器运行时交互，管理容器的生命周期，并监视容器的资源使用情况。</p><p>总之，容器运行时是Kubernetes集群中非常重要的一个组件，它负责管理容器的生命周期，并确保容器能够在隔离的环境中运行，是Kubernetes集群中实现容器编排和管理的关键组件之一。</p><h3 id="术语" tabindex="-1"><a class="header-anchor" href="#术语" aria-hidden="true">#</a> 术语</h3><p>xx</p><h3 id="kubectl常用命令" tabindex="-1"><a class="header-anchor" href="#kubectl常用命令" aria-hidden="true">#</a> <code>kubectl</code>常用命令</h3><p><code>kubectl</code>是Kubernetes的命令行工具，可以用于管理Kubernetes集群、部署应用程序、监视集群状态等操作。下面是<code>kubectl</code>的一些基本用法：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 查看kubectl版本</span>
kubectl version

<span class="token comment"># 查看配置</span>
kubectl config view

<span class="token comment"># 查看集群信息</span>
kubectl cluster-info

<span class="token comment"># 查看节点信息</span>
kubectl get nodes

<span class="token comment"># 查看命名空间信息</span>
kubectl get namespaces

<span class="token comment"># 创建一个deployment</span>
kubectl create deployment <span class="token operator">&lt;</span>deployment-name<span class="token operator">&gt;</span> <span class="token parameter variable">--image</span><span class="token operator">=</span><span class="token operator">&lt;</span>image-name<span class="token operator">&gt;</span>

<span class="token comment"># 查看deployment信息</span>
kubectl get deployments

<span class="token comment"># 查看service信息</span>
kubectl get services

<span class="token comment"># 端口转发到本地</span>
kubectl port-forward <span class="token operator">&lt;</span>pod-name<span class="token operator">&gt;</span> <span class="token operator">&lt;</span>local-port<span class="token operator">&gt;</span>:<span class="token operator">&lt;</span>pod-port<span class="token operator">&gt;</span>

<span class="token comment"># 查看pod日志</span>
kubectl logs <span class="token operator">&lt;</span>pod-name<span class="token operator">&gt;</span>

<span class="token comment"># 查看pod信息</span>
kubectl get pods

<span class="token comment"># 进入一个pod</span>
kubectl <span class="token builtin class-name">exec</span> <span class="token parameter variable">-it</span> <span class="token operator">&lt;</span>pod-name<span class="token operator">&gt;</span> <span class="token function">bash</span>

<span class="token comment"># 删除pod</span>
kubectl delete pod <span class="token operator">&lt;</span>pod-name<span class="token operator">&gt;</span>

<span class="token comment">#查看名称为nginx-XXXXXX的Pod的信息</span>
kubectl describe pod nginx-XXXXXX	

<span class="token comment">#查看名称为nginx的Deployment的信息</span>
kubectl describe deployment nginx	

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="举例" tabindex="-1"><a class="header-anchor" href="#举例" aria-hidden="true">#</a> 举例</h3><h4 id="部署" tabindex="-1"><a class="header-anchor" href="#部署" aria-hidden="true">#</a> 部署</h4><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">apiVersion</span><span class="token punctuation">:</span> apps/v1	<span class="token comment">#与k8s集群版本有关，使用 kubectl api-versions 即可查看当前集群支持的版本</span>
<span class="token key atrule">kind</span><span class="token punctuation">:</span> Deployment	<span class="token comment">#该配置的类型，我们使用的是 Deployment</span>
<span class="token key atrule">metadata</span><span class="token punctuation">:</span>	        <span class="token comment">#译名为元数据，即 Deployment 的一些基本属性和信息</span>
  <span class="token key atrule">name</span><span class="token punctuation">:</span> nginx<span class="token punctuation">-</span>deployment	<span class="token comment">#Deployment 的名称</span>
  <span class="token key atrule">labels</span><span class="token punctuation">:</span>	    <span class="token comment">#标签，可以灵活定位一个或多个资源，其中key和value均可自定义，可以定义多组，目前不需要理解</span>
    <span class="token key atrule">app</span><span class="token punctuation">:</span> nginx	<span class="token comment">#为该Deployment设置key为app，value为nginx的标签</span>
<span class="token key atrule">spec</span><span class="token punctuation">:</span>	        <span class="token comment">#这是关于该Deployment的描述，可以理解为你期待该Deployment在k8s中如何使用</span>
  <span class="token key atrule">replicas</span><span class="token punctuation">:</span> <span class="token number">1</span>	<span class="token comment">#使用该Deployment创建一个应用程序实例</span>
  <span class="token key atrule">selector</span><span class="token punctuation">:</span>	    <span class="token comment">#标签选择器，与上面的标签共同作用，目前不需要理解</span>
    <span class="token key atrule">matchLabels</span><span class="token punctuation">:</span> <span class="token comment">#选择包含标签app:nginx的资源</span>
      <span class="token key atrule">app</span><span class="token punctuation">:</span> nginx
  <span class="token key atrule">template</span><span class="token punctuation">:</span>	    <span class="token comment">#这是选择或创建的Pod的模板</span>
    <span class="token key atrule">metadata</span><span class="token punctuation">:</span>	<span class="token comment">#Pod的元数据</span>
      <span class="token key atrule">labels</span><span class="token punctuation">:</span>	<span class="token comment">#Pod的标签，上面的selector即选择包含标签app:nginx的Pod</span>
        <span class="token key atrule">app</span><span class="token punctuation">:</span> nginx
    <span class="token key atrule">spec</span><span class="token punctuation">:</span>	    <span class="token comment">#期望Pod实现的功能（即在pod中部署）</span>
      <span class="token key atrule">containers</span><span class="token punctuation">:</span>	<span class="token comment">#生成container，与docker中的container是同一种</span>
      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> nginx	<span class="token comment">#container的名称</span>
        <span class="token key atrule">image</span><span class="token punctuation">:</span> nginx<span class="token punctuation">:</span>1.7.9	<span class="token comment">#使用镜像nginx:1.7.9创建container，该container默认80端口可访问</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 启动</span>
kubectl apply <span class="token parameter variable">-f</span> nginx-deployment.yaml

<span class="token comment"># 查看 Deployment</span>
kubectl get deployments

<span class="token comment"># 查看 Pod</span>
kubectl get pods
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>`,47),b={href:"https://devopscube.com/kubernetes-tutorials-beginners/",target:"_blank",rel:"noopener noreferrer"},m={href:"https://devopscube.com/kubernetes-architecture-explained/",target:"_blank",rel:"noopener noreferrer"},k={href:"https://www.okteto.com/blog/kubernetes-basics/",target:"_blank",rel:"noopener noreferrer"},v={href:"https://kuboard.cn/",target:"_blank",rel:"noopener noreferrer"};function h(g,y){const s=r("ExternalLinkIcon");return l(),c("div",null,[p,e("blockquote",null,[e("p",null,[n("参考: "),e("a",d,[n("https://devopscube.com/kubernetes-architecture-explained/"),a(s)])])]),u,e("ol",null,[e("li",null,[e("a",b,[n("https://devopscube.com/kubernetes-tutorials-beginners/"),a(s)])]),e("li",null,[e("a",m,[n("https://devopscube.com/kubernetes-architecture-explained/"),a(s)])]),e("li",null,[e("a",k,[n("https://www.okteto.com/blog/kubernetes-basics/"),a(s)])]),e("li",null,[e("a",v,[n("https://kuboard.cn/"),a(s)])])])])}const K=o(i,[["render",h],["__file","k8s使用教程.html.vue"]]);export{K as default};
